namespace Payments;

/// <summary>Abstraction over the external payment processor (Stripe, Braintree, etc.).</summary>
public interface IPaymentProvider
{
    Task<ProviderChargeResult> CreateChargeAsync(string cardToken, decimal amount, string currency);
    Task<ProviderRefundResult> CreateRefundAsync(string chargeId, decimal amount);
}

public record ProviderChargeResult(string ChargeId, bool Approved);
public record ProviderRefundResult(string RefundId, bool Approved);

/// <summary>Coordinates charge, refund, and webhook operations.</summary>
public sealed class PaymentGateway
{
    private readonly IPaymentProvider _provider;

    public PaymentGateway(IPaymentProvider provider)
    {
        _provider = provider ?? throw new ArgumentNullException(nameof(provider));
    }

    public async Task<ChargeResult> ChargeAsync(string cardToken, decimal amount, string currency = "USD")
    {
        if (string.IsNullOrWhiteSpace(cardToken))
            throw new ArgumentException("Card token is required.", nameof(cardToken));
        if (amount <= 0)
            throw new ArgumentOutOfRangeException(nameof(amount), "Amount must be positive.");
        if (amount > 999_999.99m)
            throw new ArgumentOutOfRangeException(nameof(amount), "Amount exceeds maximum allowed.");
        if (string.IsNullOrWhiteSpace(currency) || currency.Length != 3)
            throw new ArgumentException("Currency must be a 3-letter ISO code.", nameof(currency));

        var result = await _provider.CreateChargeAsync(cardToken, amount, currency.ToUpperInvariant());
        return new ChargeResult(result.ChargeId, result.Approved);
    }

    public async Task<RefundResult> RefundAsync(string chargeId, decimal? amount = null)
    {
        if (string.IsNullOrWhiteSpace(chargeId))
            throw new ArgumentException("Charge ID is required.", nameof(chargeId));
        if (amount.HasValue && amount.Value <= 0)
            throw new ArgumentOutOfRangeException(nameof(amount), "Refund amount must be positive.");

        var refundAmount = amount ?? 0m; // 0 signals full refund to provider
        var result = await _provider.CreateRefundAsync(chargeId, refundAmount);
        return new RefundResult(result.RefundId, result.Approved);
    }

    public WebhookResult ProcessWebhook(string payload, string signature)
    {
        if (string.IsNullOrWhiteSpace(payload))
            throw new ArgumentException("Payload is required.", nameof(payload));
        if (string.IsNullOrWhiteSpace(signature))
            throw new ArgumentException("Signature is required.", nameof(signature));

        if (!VerifySignature(payload, signature))
            return new WebhookResult(WebhookStatus.InvalidSignature, EventType: null);

        var eventType = ExtractEventType(payload);
        return eventType switch
        {
            "charge.succeeded" => new WebhookResult(WebhookStatus.Processed, EventType: eventType),
            "charge.failed"    => new WebhookResult(WebhookStatus.Processed, EventType: eventType),
            "refund.created"   => new WebhookResult(WebhookStatus.Processed, EventType: eventType),
            _                  => new WebhookResult(WebhookStatus.UnknownEvent, EventType: eventType),
        };
    }

    // Simplified HMAC-style check: signature must equal "sha256=" + hex of payload length.
    private static bool VerifySignature(string payload, string signature) =>
        signature == $"sha256={payload.Length:x8}";

    private static string ExtractEventType(string payload)
    {
        // Minimal JSON-less parsing: expects "event:<type>" somewhere in the payload.
        const string marker = "event:";
        var idx = payload.IndexOf(marker, StringComparison.Ordinal);
        if (idx < 0) return "unknown";
        var start = idx + marker.Length;
        var end = payload.IndexOf(',', start);
        return end < 0 ? payload[start..].Trim() : payload[start..end].Trim();
    }
}

public record ChargeResult(string ChargeId, bool Success);
public record RefundResult(string RefundId, bool Success);
public record WebhookResult(WebhookStatus Status, string? EventType);

public enum WebhookStatus
{
    Processed,
    InvalidSignature,
    UnknownEvent,
}

