            .ReturnsAsync(new ProviderChargeResult("ch_123", Approved: true));

        var result = await _gateway.ChargeAsync("tok_valid", 49.99m);

        Assert.IsTrue(result.Success);
        Assert.AreEqual("ch_123", result.ChargeId);
        _providerMock.Verify(p => p.CreateChargeAsync("tok_valid", 49.99m, "USD"), Times.Once);
    }

    [TestMethod]
    public async Task ChargeAsync_ProviderDeclinesCard_ReturnsFailureResult()
    {
        _providerMock
            .Setup(p => p.CreateChargeAsync("tok_declined", 100m, "USD"))
            .ReturnsAsync(new ProviderChargeResult("ch_456", Approved: false));

        var result = await _gateway.ChargeAsync("tok_declined", 100m);

        Assert.IsFalse(result.Success);
        Assert.AreEqual("ch_456", result.ChargeId);
    }

    [TestMethod]
    public async Task ChargeAsync_ExplicitCurrency_PassesCurrencyToProvider()
    {
        _providerMock
            .Setup(p => p.CreateChargeAsync("tok_eu", 25m, "EUR"))
            .ReturnsAsync(new ProviderChargeResult("ch_eu", Approved: true));

        var result = await _gateway.ChargeAsync("tok_eu", 25m, currency: "eur");

        Assert.IsTrue(result.Success);
        _providerMock.Verify(p => p.CreateChargeAsync("tok_eu", 25m, "EUR"), Times.Once);
    }

    [TestMethod]
    public async Task ChargeAsync_SmallestValidAmount_Succeeds()
    {
        _providerMock
            .Setup(p => p.CreateChargeAsync("tok_penny", 0.01m, "USD"))
            .ReturnsAsync(new ProviderChargeResult("ch_penny", Approved: true));

        var result = await _gateway.ChargeAsync("tok_penny", 0.01m);

        Assert.IsTrue(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_MaxAllowedAmount_Succeeds()
    {
        _providerMock
            .Setup(p => p.CreateChargeAsync("tok_big", 999_999.99m, "USD"))
            .ReturnsAsync(new ProviderChargeResult("ch_big", Approved: true));

        var result = await _gateway.ChargeAsync("tok_big", 999_999.99m);

        Assert.IsTrue(result.Success);
    }

    // ── Validation failures ─────────────────────────────────────

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public async Task ChargeAsync_InvalidCardToken_ThrowsArgumentException(string? badToken)
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.ChargeAsync(badToken!, 10m));
    }

    [TestMethod]
    [DataRow(0)]
    [DataRow(-1)]
    [DataRow(-0.01)]
    public async Task ChargeAsync_NonPositiveAmount_ThrowsArgumentOutOfRangeException(double badAmount)
    {
        await Assert.ThrowsExceptionAsync<ArgumentOutOfRangeException>(
            () => _gateway.ChargeAsync("tok_ok", (decimal)badAmount));
    }

    [TestMethod]
    public async Task ChargeAsync_AmountExceedsMaximum_ThrowsArgumentOutOfRangeException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentOutOfRangeException>(
            () => _gateway.ChargeAsync("tok_ok", 1_000_000m));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("US")]
    [DataRow("USDD")]
    public async Task ChargeAsync_InvalidCurrency_ThrowsArgumentException(string? badCurrency)
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
