[TestClass]
public class WebhookTests
{
    private Payments.PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup()
    {
        var provider = new Mock<IPaymentProvider>();
        _gateway = new Payments.PaymentGateway(provider.Object);
    }

    // Helper: build a valid signature for the given payload.
