        Assert.IsNull(result.EventType);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void ProcessWebhook_MissingPayload_ThrowsArgumentException(string? badPayload)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _gateway.ProcessWebhook(badPayload!, "some-sig"));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void ProcessWebhook_MissingSignature_ThrowsArgumentException(string? badSig)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _gateway.ProcessWebhook("event:charge.succeeded", badSig!));
    }

    // ── Known event types ───────────────────────────────────────

    [TestMethod]
    [DataRow("charge.succeeded")]
    [DataRow("charge.failed")]
    [DataRow("refund.created")]
    public void ProcessWebhook_KnownEvent_ReturnsProcessed(string eventType)
    {
        var payload = $"event:{eventType}";
        var result = _gateway.ProcessWebhook(payload, Sign(payload));

        Assert.AreEqual(WebhookStatus.Processed, result.Status);
        Assert.AreEqual(eventType, result.EventType);
    }

    // ── Unknown / malformed events ──────────────────────────────

    [TestMethod]
    public void ProcessWebhook_UnknownEventType_ReturnsUnknownEvent()
    {
        var payload = "event:invoice.paid";
        var result = _gateway.ProcessWebhook(payload, Sign(payload));

        Assert.AreEqual(WebhookStatus.UnknownEvent, result.Status);
        Assert.AreEqual("invoice.paid", result.EventType);
    }

    [TestMethod]
    public void ProcessWebhook_NoEventMarker_ReturnsUnknownEvent()
    {
        var payload = "some random payload without marker";
        var result = _gateway.ProcessWebhook(payload, Sign(payload));

        Assert.AreEqual(WebhookStatus.UnknownEvent, result.Status);
        Assert.AreEqual("unknown", result.EventType);
    }

    [TestMethod]
    public void ProcessWebhook_EventWithTrailingComma_ExtractsCorrectly()
    {
        var payload = "event:charge.succeeded,extra:data";
        var result = _gateway.ProcessWebhook(payload, Sign(payload));

        Assert.AreEqual(WebhookStatus.Processed, result.Status);
        Assert.AreEqual("charge.succeeded", result.EventType);
    }
}

